/// Extracts the first grapheme cluster of the string and returns it as a
/// new string, or, if `count` is given, returns an array of the first
/// `count` grapheme clusters instead.
/// Fails with an error if the string is empty or if `count` is larger
/// than the number of grapheme clusters in the (optionally stripped)
/// string.
#[func]
pub fn first(
    &self,
    /// If given, returns an array of the first `count` grapheme
    /// clusters instead of a single string.
    #[named]
    count: Option<usize>,
    /// A set of characters to remove from the start of the string
    /// before extracting, if given.
    #[named]
    strip: Option<Str>,
) -> StrResult<Value> {
    let stripped = match &strip {
        Some(pattern) => {
            self.0.trim_start_matches(|c| pattern.as_str().contains(c))
        }
        None => self.0.as_str(),
    };

    match count {
        None => stripped
            .graphemes(true)
            .next()
            .map(|s| Value::Str(s.into()))
            .ok_or_else(string_is_empty),
        Some(count) => {
            let graphemes: Vec<&str> = stripped.graphemes(true).collect();
            if count > graphemes.len() {
                return Err(count_exceeds_length(count, graphemes.len()));
            }
            Ok(Value::Array(
                graphemes[..count]
                    .iter()
                    .map(|&s| Value::Str(s.into()))
                    .collect(),
            ))
        }
    }
}

