/// new string, or, if `count` is given, returns an array of the last
/// `count` grapheme clusters instead.
/// Fails with an error if the string is empty or if `count` is larger
/// than the number of grapheme clusters in the (optionally stripped)
/// string.
#[func]
pub fn last(
    &self,
    /// If given, returns an array of the last `count` grapheme
    /// clusters instead of a single string.
    #[named]
    count: Option<usize>,
    /// A set of characters to remove from the end of the string before
    /// extracting, if given.
    #[named]
    strip: Option<Str>,
) -> StrResult<Value> {
    let stripped = match &strip {
        Some(pattern) => self.0.trim_end_matches(|c| pattern.as_str().contains(c)),
